export function duplicateForm(
  overrides: Partial<InvitationData> = {},
): InvitationData {
  const { id: _id, ...form } =
    toAdminInvitationInitialData(sourceInvitationRow);
  void _id;
  return {
    ...form,
    ...overrides,
  };
}
